var breakpoints = (function() {
    "use strict";
    
    // Главная функция-конструктор
    function Breakpoints(config) {
        t.init(config);
    }
    
    // Внутренний объект с логикой библиотеки
    var t = {
        // Список breakpoint'ов, заданный пользователем
        list: null,
        
        // Кэш медиа-запросов
        media: {},
        
        // Массив обработчиков событий
        events: [],
        
        // Инициализация библиотеки с конфигурацией breakpoint'ов
        init: function(config) {
            t.list = config;
            
            // Подписываемся на события изменения размера/ориентации
            window.addEventListener("resize", t.poll);
            window.addEventListener("orientationchange", t.poll);
            window.addEventListener("load", t.poll);
            window.addEventListener("fullscreenchange", t.poll);
        },
        
        // Проверяет, активен ли указанный breakpoint
        active: function(query) {
            var operator, name, mediaQuery, value, min, max, unit;
            
            // Если медиа-запрос для этого breakpoint'а еще не создан
            if (!(query in t.media)) {
                
                // ОПРЕДЕЛЕНИЕ ОПЕРАТОРА И ИМЕНИ BREAKPOINT'а
                // Поддерживаемые операторы: >=, <=, >, <, !, =
                if (">=" == query.substr(0, 2)) {
                    operator = "gte";  // greater than or equal (больше или равно)
                    name = query.substr(2);
                } else if ("<=" == query.substr(0, 2)) {
                    operator = "lte";  // less than or equal (меньше или равно)
                    name = query.substr(2);
                } else if (">" == query.substr(0, 1)) {
                    operator = "gt";   // greater than (больше)
                    name = query.substr(1);
                } else if ("<" == query.substr(0, 1)) {
                    operator = "lt";   // less than (меньше)
                    name = query.substr(1);
                } else if ("!" == query.substr(0, 1)) {
                    operator = "not";  // not equal (не равно)
                    name = query.substr(1);
                } else {
                    operator = "eq";   // equal (равно)
                    name = query;
                }
                
                // Если имя breakpoint'а существует в конфигурации
                if (name && name in t.list) {
                    value = t.list[name];
                    
                    // Если breakpoint задан как массив [min, max]
                    if (Array.isArray(value)) {
                        // Парсим минимальное и максимальное значения
                        min = parseInt(value[0]);
                        max = parseInt(value[1]);
                        
                        // Определяем единицу измерения (px, em, rem и т.д.)
                        if (isNaN(min)) {
                            if (isNaN(max)) return;
                            unit = value[1].substr(String(max).length);
                        } else {
                            unit = value[0].substr(String(min).length);
                        }
                        
                        // ГЕНЕРАЦИЯ МЕДИА-ЗАПРОСОВ НА ОСНОВЕ ОПЕРАТОРА
                        
                        // Случай: min отсутствует (например: [null, "768px"])
                        if (isNaN(min)) {
                            switch(operator) {
                                case "gte": // >=
                                    mediaQuery = "screen";
                                    break;
                                case "lte": // <=
                                    mediaQuery = "screen and (max-width: " + max + unit + ")";
                                    break;
                                case "gt": // >
                                    mediaQuery = "screen and (min-width: " + (max + 1) + unit + ")";
                                    break;
                                case "lt": // <
                                    mediaQuery = "screen and (max-width: -1px)"; // Никогда не сработает
                                    break;
                                case "not": // !
                                    mediaQuery = "screen and (min-width: " + (max + 1) + unit + ")";
                                    break;
                                default: // =
                                    mediaQuery = "screen and (max-width: " + max + unit + ")";
                            }
                        }
                        // Случай: max отсутствует (например: ["768px", null])
                        else if (isNaN(max)) {
                            switch(operator) {
                                case "gte": // >=
                                    mediaQuery = "screen and (min-width: " + min + unit + ")";
                                    break;
                                case "lte": // <=
                                    mediaQuery = "screen";
                                    break;
                                case "gt": // >
                                    mediaQuery = "screen and (max-width: -1px)"; // Никогда не сработает
                                    break;
                                case "lt": // <
                                    mediaQuery = "screen and (max-width: " + (min - 1) + unit + ")";
                                    break;
                                case "not": // !
                                    mediaQuery = "screen and (max-width: " + (min - 1) + unit + ")";
                                    break;
                                default: // =
                                    mediaQuery = "screen and (min-width: " + min + unit + ")";
                            }
                        }
                        // Оба значения присутствуют (например: ["768px", "1024px"])
                        else {
                            switch(operator) {
                                case "gte": // >=
                                    mediaQuery = "screen and (min-width: " + min + unit + ")";
                                    break;
                                case "lte": // <=
                                    mediaQuery = "screen and (max-width: " + max + unit + ")";
                                    break;
                                case "gt": // >
                                    mediaQuery = "screen and (min-width: " + (max + 1) + unit + ")";
                                    break;
                                case "lt": // <
                                    mediaQuery = "screen and (max-width: " + (min - 1) + unit + ")";
                                    break;
                                case "not": // !
                                    // ВАЖНО! Этот оператор создает сложный медиа-запрос
                                    // который будет срабатывать КРОМЕ диапазона min-max
                                    mediaQuery = "screen and (max-width: " + (min - 1) + unit + "), " +
                                                 "screen and (min-width: " + (max + 1) + unit + ")";
                                    break;
                                default: // =
                                    // Стандартный диапазон от min до max
                                    mediaQuery = "screen and (min-width: " + min + unit + ") and " +
                                                 "(max-width: " + max + unit + ")";
                            }
                        }
                    }
                    // Если breakpoint задан как строка (пользовательский медиа-запрос)
                    else {
                        // Если строка начинается с "(" - это уже готовый медиа-запрос
                        // Добавляем "screen and " перед ним
                        mediaQuery = ("(" == value.charAt(0)) ? 
                                    "screen and " + value : 
                                    value;
                    }
                    
                    // Кэшируем созданный медиа-запрос
                    t.media[query] = !!mediaQuery && mediaQuery;
                }
            }
            
            // Проверяем, соответствует ли текущее окно медиа-запросу
            return t.media[query] !== false && 
                   window.matchMedia(t.media[query]).matches;
        },
        
        // Регистрация обработчика для breakpoint'а
        // ВАЖНО ДЛЯ ВАШЕЙ ПРОБЛЕМЫ: 
        // Именно здесь могут быть обработчики, которые меняют прозрачность фона!
        on: function(query, handler) {
            // Добавляем обработчик в массив событий
            t.events.push({
                query: query,
                handler: handler,
                state: false  // Текущее состояние: сработал или нет
            });
            
            // Если breakpoint уже активен, сразу вызываем обработчик
            if (t.active(query)) {
                handler();
            }
        },
        
        // Проверка всех зарегистрированных breakpoint'ов
        poll: function() {
            var i, event;
            
            // Перебираем все зарегистрированные обработчики
            for (i = 0; i < t.events.length; i++) {
                event = t.events[i];
                
                // ВАЖНО ДЛЯ ВАШЕЙ ПРОБЛЕМЫ:
                // Этот код проверяет состояние breakpoint'ов при каждом изменении размера окна
                // Если у вас есть обработчик для <980px, он будет вызываться здесь
                
                if (t.active(event.query)) {
                    // Если breakpoint активен и обработчик еще не срабатывал
                    if (!event.state) {
                        event.state = true;
                        // ВЫЗОВ ОБРАБОТЧИКА!
                        // Здесь может быть код, который меняет background с градиента на сплошной цвет
                        // или убирает прозрачность
                        event.handler();
                    }
                } else {
                    // Если breakpoint не активен, но обработчик срабатывал ранее
                    if (event.state) {
                        event.state = false;
                        // Здесь может быть код, который возвращает исходный background
                    }
                }
            }
        }
    };
    
    // Публичное API библиотеки
    Breakpoints._ = t;  // Для отладки и расширения
    
    // Метод для регистрации обработчиков breakpoint'ов
    Breakpoints.on = function(query, handler) {
        t.on(query, handler);
    };
    
    // Метод для проверки активности breakpoint'а
    Breakpoints.active = function(query) {
        return t.active(query);
    };
    
    return Breakpoints;
})();

// UMD обертка для поддержки разных модульных систем
(function(global, factory) {
    // Поддержка AMD (Require.js)
    if (typeof define === "function" && define.amd) {
        define([], factory);
    } 
    // Поддержка CommonJS (Node.js)
    else if (typeof exports === "object") {
        module.exports = factory();
    } 
    // Глобальная переменная для браузера
    else {
        global.breakpoints = factory();
    }
})(this, function() {
    return breakpoints;
});